mapper.select:
select count(1)
from xf_approve_flow_config
where apply_dept_id = #{applyDeptId}
  and status = '0'

  and id != #{excludeId}

mapper.insert:
insert into xf_approve_flow_config(
    flow_name, apply_dept_id, apply_dept_name, status, remark, create_by, create_time
) values (
    #{flowName}, #{applyDeptId}, #{applyDeptName}, #{status}, #{remark}, #{createBy}, sysdate()
)

mapper.update:
update xf_approve_flow_config
flow_name = #{flowName}, apply_dept_id = #{applyDeptId}, apply_dept_name = #{applyDeptName}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where id = #{id}

mapper.delete:
delete from xf_approve_flow_stage_dept where stage_id in (
    select id from xf_approve_flow_stage where flow_config_id = #{flowConfigId}
)
